//! Purpose:
//! Builds callable descriptor support reused by eval-to-native constructor and
//! method bridges.
//!
//! Called from:
//! - `crate::codegen_ir::finalize_user_asm()`.
//! - `crate::codegen_ir::eval_constructor_helpers` and
//!   `crate::codegen_ir::eval_method_helpers`.
//!
//! Key details:
//! - Eval stores PHP callbacks as boxed runtime values, while AOT callable
//!   parameters expect descriptor pointers.
//! - String callables and static callable arrays select static descriptors with
//!   uniform invokers generated by the existing callable dispatch machinery.

use crate::codegen::abi;
use crate::codegen::callable_descriptor::{
    self, CallableDescriptorInvocation, CallableDescriptorShape,
};
use crate::codegen::callable_dispatch::{
    self, RuntimeCallableCase, RuntimeCallableSelector, RuntimeInstanceCallableShape,
    RuntimeInstanceMethodCallableCase, RuntimeStaticMethodCallableCase,
};
use crate::codegen::context::DeferredClosure;
use crate::codegen::data_section::DataSection;
use crate::codegen::emit::Emitter;
use crate::ir::{Function, LocalKind, Module};
use crate::names::{function_symbol, php_symbol_key};
use crate::parser::ast::{Expr, ExprKind, Stmt, StmtKind, Visibility};
use crate::span::Span;
use crate::types::{callable_wrapper_sig, FunctionSig, PhpType};

const EVAL_RECEIVER_CAPTURE_PARAM: &str = "__elephc_eval_callable_receiver";
const MIXED_METHOD_TAG_OFFSET: usize = 0;
const MIXED_METHOD_PAYLOAD_OFFSET: usize = 16;
const MIXED_RECEIVER_TAG_OFFSET: usize = 32;
const MIXED_RECEIVER_PAYLOAD_OFFSET: usize = 48;
const MIXED_SELECTOR_BYTES: usize = 64;
const SAVED_OBJECT_RECEIVER_BYTES: usize = 16;
const MIXED_TAG_STRING: i64 = 1;
const MIXED_TAG_OBJECT: i64 = 6;
const EVAL_DYNAMIC_CALLABLE_INVOKER_LABEL: &str = "__elephc_eval_dynamic_callable_invoker";
const EVAL_DYNAMIC_CALLABLE_ENTRY_LABEL: &str = "__elephc_eval_dynamic_callable_entry";
const EVAL_DYNAMIC_CONTEXT_CAPTURE: usize = 0;
const EVAL_DYNAMIC_CALLBACK_CAPTURE: usize = 1;
const EVAL_DYNAMIC_CALLABLE_CAPTURE_BYTES: usize = 32;
const AARCH64_EVAL_CONTEXT_FROM_FP_OFFSET: i64 = 16;

/// Callable descriptors available to eval constructor and method bridges.
pub(super) struct EvalCallableDescriptorSupport {
    string_cases: Vec<RuntimeCallableCase>,
    instance_array_cases: Vec<RuntimeInstanceMethodCallableCase>,
    static_array_cases: Vec<RuntimeStaticMethodCallableCase>,
    object_cases: Vec<RuntimeInstanceMethodCallableCase>,
    dynamic_descriptor_label: Option<String>,
}

impl EvalCallableDescriptorSupport {
    /// Returns true when no callable descriptor case is available.
    pub(super) fn is_empty(&self) -> bool {
        self.string_cases.is_empty()
            && self.instance_array_cases.is_empty()
            && self.static_array_cases.is_empty()
            && self.object_cases.is_empty()
    }

    /// Returns true when no callable-array descriptor case is available.
    fn array_cases_empty(&self) -> bool {
        self.instance_array_cases.is_empty() && self.static_array_cases.is_empty()
    }

    /// Returns true when no invokable-object descriptor case is available.
    fn object_cases_empty(&self) -> bool {
        self.object_cases.is_empty()
    }

    /// Returns true when eval callback fallback descriptors can be materialized.
    fn has_dynamic_descriptor(&self) -> bool {
        self.dynamic_descriptor_label.is_some()
    }
}

/// Returns true when eval bridges may need to turn PHP callbacks into descriptors.
pub(super) fn module_needs_eval_callable_descriptor_support(module: &Module) -> bool {
    module_uses_eval(module) && module_has_callable_aot_method_param(module)
}

/// Returns true when the EIR module contains a function that can call eval.
fn module_uses_eval(module: &Module) -> bool {
    all_module_functions(module).any(function_uses_eval)
}

/// Iterates every EIR function body emitted or inspected by the backend.
fn all_module_functions(module: &Module) -> impl Iterator<Item = &Function> {
    module
        .functions
        .iter()
        .chain(module.class_methods.iter())
        .chain(module.closures.iter())
        .chain(module.fiber_wrappers.iter())
        .chain(module.callback_wrappers.iter())
        .chain(module.extern_callback_trampolines.iter())
        .chain(module.runtime_callable_invokers.iter())
}

/// Returns true when a function has hidden eval state locals.
fn function_uses_eval(function: &Function) -> bool {
    function.locals.iter().any(|local| {
        matches!(
            local.kind,
            LocalKind::EvalContext | LocalKind::EvalScope | LocalKind::EvalGlobalScope
        )
    })
}

/// Returns true when any generated class callable exposed to eval accepts `callable`.
fn module_has_callable_aot_method_param(module: &Module) -> bool {
    module.class_infos.values().any(|class_info| {
        class_info.methods.values().any(signature_has_callable_param)
            || class_info
                .static_methods
                .values()
                .any(signature_has_callable_param)
    })
}

/// Returns true when one signature contains a callable ABI parameter.
fn signature_has_callable_param(signature: &crate::types::FunctionSig) -> bool {
    signature
        .params
        .iter()
        .any(|(_, ty)| ty.codegen_repr() == PhpType::Callable)
}

/// Emits shared runtime callable wrappers/invokers and returns descriptor cases.
pub(super) fn emit_eval_callable_descriptor_support(
    module: &Module,
    emitter: &mut Emitter,
    data: &mut DataSection,
    needed: bool,
) -> EvalCallableDescriptorSupport {
    if !needed {
        return EvalCallableDescriptorSupport {
            string_cases: Vec::new(),
            instance_array_cases: Vec::new(),
            static_array_cases: Vec::new(),
            object_cases: Vec::new(),
            dynamic_descriptor_label: None,
        };
    }
    let mut legacy_ctx = super::lower_inst::legacy_context_from_eir_module(module);
    legacy_ctx.functions.retain(|name, _| {
        module
            .functions
            .iter()
            .any(|function| !function.flags.is_main && function.name == *name)
    });
    let string_cases = eval_user_function_callable_cases(&mut legacy_ctx, data);
    let instance_array_cases = eval_instance_method_callable_cases(module, &mut legacy_ctx, data);
    let static_array_cases = eval_static_method_callable_cases(module, &mut legacy_ctx, data);
    let object_cases = eval_invokable_object_callable_cases(module, &mut legacy_ctx, data);
    let dynamic_descriptor_label = Some(eval_dynamic_callable_descriptor(data));
    emit_eval_dynamic_callable_invoker(module, emitter, data);
    emit_deferred_callable_support(emitter, data, &mut legacy_ctx);
    EvalCallableDescriptorSupport {
        string_cases,
        instance_array_cases,
        static_array_cases,
        object_cases,
        dynamic_descriptor_label,
    }
}

/// Emits the static descriptor template for eval-owned callback values.
fn eval_dynamic_callable_descriptor(data: &mut DataSection) -> String {
    let captures = vec![
        (
            "__elephc_eval_callable_context".to_string(),
            PhpType::Int,
            false,
        ),
        (
            "__elephc_eval_callable_value".to_string(),
            PhpType::Mixed,
            false,
        ),
    ];
    callable_descriptor::static_descriptor_with_optional_invoker_meta(
        data,
        EVAL_DYNAMIC_CALLABLE_ENTRY_LABEL,
        Some("eval callback"),
        callable_descriptor::CALLABLE_DESC_KIND_CALLBACK_ADAPTER,
        None,
        &captures,
        &[],
        CallableDescriptorInvocation::new(CallableDescriptorShape::CallbackAdapter),
        Some(EVAL_DYNAMIC_CALLABLE_INVOKER_LABEL),
    )
}

/// Emits the uniform invoker for descriptors that capture an eval callback value.
fn emit_eval_dynamic_callable_invoker(
    module: &Module,
    emitter: &mut Emitter,
    data: &mut DataSection,
) {
    emitter.blank();
    emitter.comment("--- eval bridge: dynamic callable descriptor invoker ---");
    emitter.label(EVAL_DYNAMIC_CALLABLE_ENTRY_LABEL);
    emitter.instruction("ret");                                                 // direct entry calls are never used for eval dynamic descriptors
    emitter.label_global(EVAL_DYNAMIC_CALLABLE_INVOKER_LABEL);
    match module.target.arch {
        crate::codegen::platform::Arch::AArch64 => {
            emit_aarch64_eval_dynamic_callable_invoker(module, emitter, data);
        }
        crate::codegen::platform::Arch::X86_64 => {
            emit_x86_64_eval_dynamic_callable_invoker(module, emitter, data);
        }
    }
}

/// Emits the ARM64 body for eval dynamic callable descriptor invocation.
fn emit_aarch64_eval_dynamic_callable_invoker(
    module: &Module,
    emitter: &mut Emitter,
    data: &mut DataSection,
) {
    let throwable_label = "__elephc_eval_dynamic_callable_throwable";
    let fatal_label = "__elephc_eval_dynamic_callable_fatal";
    let done_label = "__elephc_eval_dynamic_callable_done";
    let symbol = module
        .target
        .extern_symbol("__elephc_eval_callable_call_array");
    emitter.instruction("sub sp, sp, #64");                                     // reserve descriptor, arg-array, eval result, and saved frame slots
    emitter.instruction("stp x29, x30, [sp, #48]");                             // preserve the caller frame around the Rust callback
    emitter.instruction("add x29, sp, #48");                                    // establish a stable invoker frame pointer
    emitter.instruction("str x0, [sp, #0]");                                    // save the runtime callable descriptor pointer
    emitter.instruction("str x1, [sp, #8]");                                    // save the boxed Mixed invoker argument array
    emitter.instruction("str xzr, [sp, #16]");                                  // clear result kind and padding before the FFI call
    emitter.instruction("str xzr, [sp, #24]");                                  // clear result value pointer before the FFI call
    emitter.instruction("str xzr, [sp, #32]");                                  // clear result error pointer before the FFI call
    emitter.instruction("ldr x9, [sp, #0]");                                    // reload descriptor before reading eval captures
    emitter.instruction(&format!(
        "ldr x0, [x9, #{}]",
        dynamic_capture_offset(EVAL_DYNAMIC_CONTEXT_CAPTURE)
    ));                                                                          // pass the captured eval context as FFI argument 1
    emitter.instruction(&format!(
        "ldr x1, [x9, #{}]",
        dynamic_capture_offset(EVAL_DYNAMIC_CALLBACK_CAPTURE)
    ));                                                                          // pass the captured eval callback as FFI argument 2
    emitter.instruction("ldr x2, [sp, #8]");                                    // pass the boxed Mixed invoker argument array
    emitter.instruction("add x3, sp, #16");                                     // pass writable eval result storage
    abi::emit_call_label(emitter, &symbol);
    emitter.instruction("cmp w0, #0");                                          // did magician complete callback dispatch successfully?
    emitter.instruction(&format!("b.eq {}", done_label));                       // return the boxed result on success
    emitter.instruction("cmp w0, #3");                                          // status 3 means an eval Throwable escaped
    emitter.instruction(&format!("b.eq {}", throwable_label));                  // publish the Throwable through native unwinding
    emitter.label(fatal_label);
    emit_aarch64_eval_dynamic_callable_fatal(emitter, data);
    emitter.label(throwable_label);
    emitter.instruction("ldr x0, [sp, #32]");                                   // load the boxed Throwable returned by magician
    emitter.instruction("bl __rt_mixed_unbox");                                 // expose the Throwable object payload
    abi::emit_store_reg_to_symbol(emitter, "x1", "_exc_value", 0);
    emitter.instruction("bl __rt_throw_current");                               // enter the native Throwable unwinder
    emitter.label(done_label);
    emitter.instruction("ldr x0, [sp, #24]");                                   // return the boxed Mixed callback result
    emitter.instruction("ldp x29, x30, [sp, #48]");                             // restore the caller frame
    emitter.instruction("add sp, sp, #64");                                     // release invoker scratch storage
    emitter.instruction("ret");                                                 // return to the descriptor invoker caller
}

/// Emits the x86_64 body for eval dynamic callable descriptor invocation.
fn emit_x86_64_eval_dynamic_callable_invoker(
    module: &Module,
    emitter: &mut Emitter,
    data: &mut DataSection,
) {
    let throwable_label = "__elephc_eval_dynamic_callable_throwable_x";
    let fatal_label = "__elephc_eval_dynamic_callable_fatal_x";
    let done_label = "__elephc_eval_dynamic_callable_done_x";
    let symbol = module
        .target
        .extern_symbol("__elephc_eval_callable_call_array");
    emitter.instruction("push rbp");                                            // preserve the caller frame pointer
    emitter.instruction("mov rbp, rsp");                                        // establish a stable invoker frame pointer
    emitter.instruction("sub rsp, 64");                                         // reserve descriptor, arg-array, and eval result slots
    emitter.instruction("mov QWORD PTR [rbp - 8], rdi");                        // save the runtime callable descriptor pointer
    emitter.instruction("mov QWORD PTR [rbp - 16], rsi");                       // save the boxed Mixed invoker argument array
    emitter.instruction("mov QWORD PTR [rbp - 48], 0");                         // clear result kind and padding before the FFI call
    emitter.instruction("mov QWORD PTR [rbp - 40], 0");                         // clear result value pointer before the FFI call
    emitter.instruction("mov QWORD PTR [rbp - 32], 0");                         // clear result error pointer before the FFI call
    emitter.instruction("mov r9, QWORD PTR [rbp - 8]");                         // reload descriptor before reading eval captures
    emitter.instruction(&format!(
        "mov rdi, QWORD PTR [r9 + {}]",
        dynamic_capture_offset(EVAL_DYNAMIC_CONTEXT_CAPTURE)
    ));                                                                          // pass the captured eval context as FFI argument 1
    emitter.instruction(&format!(
        "mov rsi, QWORD PTR [r9 + {}]",
        dynamic_capture_offset(EVAL_DYNAMIC_CALLBACK_CAPTURE)
    ));                                                                          // pass the captured eval callback as FFI argument 2
    emitter.instruction("mov rdx, QWORD PTR [rbp - 16]");                       // pass the boxed Mixed invoker argument array
    emitter.instruction("lea rcx, [rbp - 48]");                                 // pass writable eval result storage
    abi::emit_call_label(emitter, &symbol);
    emitter.instruction("test eax, eax");                                       // did magician complete callback dispatch successfully?
    emitter.instruction(&format!("je {}", done_label));                         // return the boxed result on success
    emitter.instruction("cmp eax, 3");                                          // status 3 means an eval Throwable escaped
    emitter.instruction(&format!("je {}", throwable_label));                    // publish the Throwable through native unwinding
    emitter.label(fatal_label);
    emit_x86_64_eval_dynamic_callable_fatal(emitter, data);
    emitter.label(throwable_label);
    emitter.instruction("mov rax, QWORD PTR [rbp - 32]");                       // load the boxed Throwable returned by magician
    emitter.instruction("call __rt_mixed_unbox");                               // expose the Throwable object payload
    abi::emit_store_reg_to_symbol(emitter, "rdi", "_exc_value", 0);
    emitter.instruction("call __rt_throw_current");                             // enter the native Throwable unwinder
    emitter.label(done_label);
    emitter.instruction("mov rax, QWORD PTR [rbp - 40]");                       // return the boxed Mixed callback result
    emitter.instruction("mov rsp, rbp");                                        // discard invoker scratch storage
    emitter.instruction("pop rbp");                                             // restore the caller frame pointer
    emitter.instruction("ret");                                                 // return to the descriptor invoker caller
}

/// Returns the byte offset for one dynamic eval callable descriptor capture.
fn dynamic_capture_offset(index: usize) -> usize {
    callable_descriptor::CALLABLE_DESC_RUNTIME_CAPTURE_OFFSET + index * 16
}

/// Emits an ARM64 fatal diagnostic for failed eval callback dispatch.
fn emit_aarch64_eval_dynamic_callable_fatal(emitter: &mut Emitter, data: &mut DataSection) {
    let (message_label, message_len) =
        data.add_string(b"Fatal error: eval callback dispatch failed\n");
    emitter.instruction("mov x0, #2");                                          // write the eval callback diagnostic to stderr
    emitter.adrp("x1", &message_label);
    emitter.add_lo12("x1", "x1", &message_label);
    emitter.instruction(&format!("mov x2, #{}", message_len));                  // pass the diagnostic byte length to write
    emitter.syscall(4);
    abi::emit_exit(emitter, 1);
}

/// Emits an x86_64 fatal diagnostic for failed eval callback dispatch.
fn emit_x86_64_eval_dynamic_callable_fatal(emitter: &mut Emitter, data: &mut DataSection) {
    let (message_label, message_len) =
        data.add_string(b"Fatal error: eval callback dispatch failed\n");
    emitter.instruction("mov edi, 2");                                          // write the eval callback diagnostic to stderr
    abi::emit_symbol_address(emitter, "rsi", &message_label);
    emitter.instruction(&format!("mov edx, {}", message_len));                  // pass the diagnostic byte length to write
    emitter.instruction("mov eax, 1");                                          // Linux x86_64 syscall 1 = write
    emitter.instruction("syscall");                                             // emit the fatal diagnostic before terminating
    abi::emit_exit(emitter, 1);
}

/// Builds descriptor cases for user functions visible as eval string callables.
fn eval_user_function_callable_cases(
    legacy_ctx: &mut crate::codegen::context::Context,
    data: &mut DataSection,
) -> Vec<RuntimeCallableCase> {
    let mut functions = legacy_ctx
        .functions
        .iter()
        .map(|(name, sig)| (name.clone(), sig.clone()))
        .collect::<Vec<_>>();
    functions.sort_by(|left, right| left.0.cmp(&right.0));
    let mut cases = Vec::with_capacity(functions.len());
    for (name, sig) in functions {
        let case_sig = callable_wrapper_sig(&sig);
        let invoker_label =
            callable_dispatch::ensure_runtime_descriptor_invoker(legacy_ctx, &[], &case_sig);
        let descriptor_label = callable_descriptor::static_descriptor_with_optional_invoker_meta(
            data,
            &function_symbol(&name),
            Some(&name),
            callable_descriptor::CALLABLE_DESC_KIND_FUNCTION,
            Some(&case_sig),
            &[],
            &[],
            CallableDescriptorInvocation::named(CallableDescriptorShape::Function, &name),
            invoker_label.as_deref(),
        );
        cases.push(RuntimeCallableCase {
            label: function_symbol(&name),
            descriptor_label,
            php_name: Some(name),
            sig: case_sig,
            captures: Vec::new(),
            has_invoker: invoker_label.is_some(),
            invoker_label,
        });
    }
    cases
}

/// Builds descriptor cases for emitted public instance methods visible to eval.
fn eval_instance_method_callable_cases(
    module: &Module,
    legacy_ctx: &mut crate::codegen::context::Context,
    data: &mut DataSection,
) -> Vec<RuntimeInstanceMethodCallableCase> {
    eval_instance_callable_cases(
        module,
        legacy_ctx,
        data,
        RuntimeInstanceCallableShape::InstanceMethod,
        |_| true,
    )
}

/// Builds descriptor cases for emitted public `__invoke` methods visible to eval.
fn eval_invokable_object_callable_cases(
    module: &Module,
    legacy_ctx: &mut crate::codegen::context::Context,
    data: &mut DataSection,
) -> Vec<RuntimeInstanceMethodCallableCase> {
    eval_instance_callable_cases(
        module,
        legacy_ctx,
        data,
        RuntimeInstanceCallableShape::ObjectInvoke,
        |method_name| php_symbol_key(method_name) == "__invoke",
    )
}

/// Builds receiver-bound descriptor cases for public emitted instance methods.
fn eval_instance_callable_cases(
    module: &Module,
    legacy_ctx: &mut crate::codegen::context::Context,
    data: &mut DataSection,
    shape: RuntimeInstanceCallableShape,
    include_method: impl Fn(&str) -> bool,
) -> Vec<RuntimeInstanceMethodCallableCase> {
    let emitted_methods = super::eir_class_method_keys(module);
    let mut candidates = Vec::new();
    for (class_name, class_info) in &module.class_infos {
        for method_name in class_info.methods.keys() {
            if !include_method(method_name) {
                continue;
            }
            if !class_info
                .method_visibilities
                .get(method_name)
                .is_some_and(|visibility| matches!(visibility, Visibility::Public))
            {
                continue;
            }
            let method_key = php_symbol_key(method_name);
            let impl_class = class_info
                .method_impl_classes
                .get(&method_key)
                .map(String::as_str)
                .unwrap_or(class_name);
            if emitted_methods.contains(&(impl_class.to_string(), method_key, false)) {
                candidates.push((
                    class_name.clone(),
                    class_info.class_id,
                    method_name.clone(),
                ));
            }
        }
    }
    candidates.sort_by(|left, right| (&left.0, &left.2).cmp(&(&right.0, &right.2)));
    candidates
        .into_iter()
        .filter_map(|(class_name, class_id, method_name)| {
            receiver_bound_instance_method_case(
                legacy_ctx,
                data,
                &class_name,
                &method_name,
                shape,
            )
            .map(|case| RuntimeInstanceMethodCallableCase {
                class_id,
                method_name,
                case,
            })
        })
        .collect()
}

/// Builds descriptor cases for emitted public static methods visible to eval.
fn eval_static_method_callable_cases(
    module: &Module,
    legacy_ctx: &mut crate::codegen::context::Context,
    data: &mut DataSection,
) -> Vec<RuntimeStaticMethodCallableCase> {
    let emitted_methods = super::eir_class_method_keys(module);
    let mut candidates = Vec::new();
    for (class_name, class_info) in &module.class_infos {
        for method_name in class_info.static_methods.keys() {
            if !class_info
                .static_method_visibilities
                .get(method_name)
                .is_some_and(|visibility| matches!(visibility, Visibility::Public))
            {
                continue;
            }
            let method_key = crate::names::php_symbol_key(method_name);
            let impl_class = class_info
                .static_method_impl_classes
                .get(&method_key)
                .map(String::as_str)
                .unwrap_or(class_name);
            if emitted_methods.contains(&(impl_class.to_string(), method_key, true)) {
                candidates.push((class_name.clone(), method_name.clone()));
            }
        }
    }
    candidates.sort_by(|left, right| (&left.0, &left.1).cmp(&(&right.0, &right.1)));
    candidates
        .into_iter()
        .filter_map(|(class_name, method_name)| {
            callable_dispatch::runtime_static_method_case(
                legacy_ctx,
                data,
                &class_name,
                &method_name,
            )
            .map(|case| RuntimeStaticMethodCallableCase {
                class_name,
                method_name,
                case,
            })
        })
        .collect()
}

/// Builds a receiver-bound descriptor case for one public instance method.
fn receiver_bound_instance_method_case(
    legacy_ctx: &mut crate::codegen::context::Context,
    data: &mut DataSection,
    class_name: &str,
    method_name: &str,
    shape: RuntimeInstanceCallableShape,
) -> Option<RuntimeCallableCase> {
    let (resolved_method_name, sig) = {
        let class_info = legacy_ctx.classes.get(class_name)?;
        let method_key = php_symbol_key(method_name);
        let (resolved_method_name, sig) = class_info
            .methods
            .iter()
            .find(|(candidate, _)| php_symbol_key(candidate) == method_key)?;
        if !class_info
            .method_visibilities
            .get(resolved_method_name)
            .is_some_and(|visibility| matches!(visibility, Visibility::Public))
        {
            return None;
        }
        (resolved_method_name.clone(), sig.clone())
    };

    let case_sig = callable_wrapper_sig(&sig);
    let hidden_name = unique_hidden_param(EVAL_RECEIVER_CAPTURE_PARAM, &case_sig);
    let capture_ty = PhpType::Object(class_name.to_string());
    let captures = vec![(hidden_name.clone(), capture_ty.clone(), false)];
    let hidden_params = vec![(hidden_name.clone(), capture_ty, false)];
    let wrapper_label = legacy_ctx.next_label("eval_callable_instance_method");
    let params = case_sig
        .params
        .iter()
        .map(|(name, _)| name.clone())
        .collect::<Vec<_>>();
    legacy_ctx.deferred_closures.push(DeferredClosure {
        label: wrapper_label.clone(),
        params,
        body: receiver_bound_instance_method_wrapper_body(
            &hidden_name,
            &resolved_method_name,
            &case_sig,
        ),
        sig: case_sig.clone(),
        captures: captures.clone(),
        hidden_params: hidden_params.clone(),
        current_class: Some(class_name.to_string()),
        needed: true,
    });

    let invoker_label =
        callable_dispatch::ensure_runtime_descriptor_invoker(legacy_ctx, &hidden_params, &case_sig);
    let (kind, invocation_shape) = match shape {
        RuntimeInstanceCallableShape::ObjectInvoke => (
            callable_descriptor::CALLABLE_DESC_KIND_OBJECT_INVOKE,
            CallableDescriptorShape::ObjectInvoke,
        ),
        RuntimeInstanceCallableShape::InstanceMethod => (
            callable_descriptor::CALLABLE_DESC_KIND_INSTANCE_METHOD,
            CallableDescriptorShape::InstanceMethod,
        ),
    };
    let php_name = format!("{}::{}", class_name, resolved_method_name);
    let descriptor_label = callable_descriptor::static_descriptor_with_optional_invoker_meta(
        data,
        &wrapper_label,
        Some(&php_name),
        kind,
        Some(&case_sig),
        &captures,
        &hidden_params,
        CallableDescriptorInvocation::method(
            invocation_shape,
            Some(class_name.to_string()),
            resolved_method_name,
        ),
        invoker_label.as_deref(),
    );
    Some(RuntimeCallableCase {
        label: wrapper_label,
        descriptor_label,
        php_name: Some(php_name),
        sig: case_sig,
        captures,
        has_invoker: invoker_label.is_some(),
        invoker_label,
    })
}

/// Builds the synthetic wrapper body for a receiver-bound eval callable descriptor.
fn receiver_bound_instance_method_wrapper_body(
    receiver_param: &str,
    method_name: &str,
    sig: &FunctionSig,
) -> Vec<Stmt> {
    let last_param_idx = sig.params.len().saturating_sub(1);
    let args = sig
        .params
        .iter()
        .enumerate()
        .map(|(idx, (name, _))| {
            let var = Expr::new(ExprKind::Variable(name.clone()), Span::dummy());
            if sig.variadic.is_some() && idx == last_param_idx {
                Expr::new(ExprKind::Spread(Box::new(var)), Span::dummy())
            } else {
                var
            }
        })
        .collect();
    let call = Expr::new(
        ExprKind::MethodCall {
            object: Box::new(Expr::new(
                ExprKind::Variable(receiver_param.to_string()),
                Span::dummy(),
            )),
            method: method_name.to_string(),
            args,
        },
        Span::dummy(),
    );
    if sig.return_type == PhpType::Void {
        vec![
            Stmt::new(StmtKind::ExprStmt(call), Span::dummy()),
            Stmt::new(StmtKind::Return(None), Span::dummy()),
        ]
    } else {
        vec![Stmt::new(StmtKind::Return(Some(call)), Span::dummy())]
    }
}

/// Returns a hidden receiver parameter name that cannot collide with visible parameters.
fn unique_hidden_param(base: &str, sig: &FunctionSig) -> String {
    if !sig.params.iter().any(|(name, _)| name == base) {
        return base.to_string();
    }
    let mut index = 0usize;
    loop {
        let candidate = format!("{}_{}", base, index);
        if !sig.params.iter().any(|(name, _)| name == &candidate) {
            return candidate;
        }
        index += 1;
    }
}

/// Emits deferred callable support bodies behind one jump.
fn emit_deferred_callable_support(
    emitter: &mut Emitter,
    data: &mut DataSection,
    legacy_ctx: &mut crate::codegen::context::Context,
) {
    if legacy_ctx.deferred_closures.is_empty()
        && legacy_ctx.deferred_fiber_wrappers.is_empty()
        && legacy_ctx.deferred_callback_wrappers.is_empty()
        && legacy_ctx.deferred_extern_callback_trampolines.is_empty()
        && legacy_ctx.deferred_runtime_callable_invokers.is_empty()
    {
        return;
    }
    let done_label = legacy_ctx.next_label("eval_callable_support_done");
    abi::emit_jump(emitter, &done_label);
    crate::codegen::emit_deferred_closures(emitter, data, legacy_ctx);
    emitter.label(&done_label);
}

/// Converts the ARM64 boxed eval argument slot into a callable descriptor pointer.
pub(super) fn emit_aarch64_cast_eval_callable_arg(
    module: &Module,
    emitter: &mut Emitter,
    data: &mut DataSection,
    support: &EvalCallableDescriptorSupport,
    label_prefix: &str,
    fail_label: &str,
) {
    let string_label = format!("{}_callable_string", label_prefix);
    let array_label = format!("{}_callable_array", label_prefix);
    let object_label = format!("{}_callable_object", label_prefix);
    let dynamic_label = format!("{}_callable_dynamic", label_prefix);
    let miss_label = if support.has_dynamic_descriptor() {
        dynamic_label.as_str()
    } else {
        fail_label
    };
    emitter.instruction("ldr x0, [x29, #-16]");                                 // reload the boxed eval argument for callable validation
    emitter.instruction("bl __rt_mixed_unbox");                                 // expose the eval callable tag and payload words
    emitter.instruction("cmp x0, #1");                                          // runtime tag 1 means a string callable name
    emitter.instruction(&format!("b.eq {}", string_label));                     // resolve string callables through descriptor metadata
    emitter.instruction("cmp x0, #4");                                          // runtime tag 4 means an indexed callable array
    emitter.instruction(&format!("b.eq {}", array_label));                      // resolve static callable arrays through descriptor metadata
    emitter.instruction("cmp x0, #5");                                          // runtime tag 5 means an associative callable array
    emitter.instruction(&format!("b.eq {}", array_label));                      // resolve static callable arrays with numeric keys
    emitter.instruction("cmp x0, #6");                                          // runtime tag 6 means an invokable object candidate
    emitter.instruction(&format!("b.eq {}", object_label));                     // resolve invokable objects through descriptor metadata
    abi::emit_jump(emitter, miss_label);
    emitter.label(&string_label);
    abi::emit_push_reg_pair(emitter, "x1", "x2");
    emit_eval_string_callable_descriptor_lookup(
        module,
        emitter,
        data,
        support,
        label_prefix,
        miss_label,
        "x0",
    );
    abi::emit_jump(emitter, &format!("{}_callable_cast_done", label_prefix));
    emitter.label(&array_label);
    emit_aarch64_eval_callable_array_selector_slots(module, emitter);
    emit_eval_callable_array_descriptor_lookup(
        emitter,
        data,
        support,
        label_prefix,
        miss_label,
        "x0",
    );
    abi::emit_jump(emitter, &format!("{}_callable_cast_done", label_prefix));
    emitter.label(&object_label);
    abi::emit_push_reg(emitter, "x1");
    emit_eval_invokable_object_descriptor_lookup(
        emitter,
        support,
        label_prefix,
        miss_label,
        "x0",
    );
    if support.has_dynamic_descriptor() {
        emitter.label(&dynamic_label);
        emit_aarch64_eval_dynamic_callable_descriptor(
            module,
            emitter,
            support,
            fail_label,
            "x0",
        );
        abi::emit_jump(emitter, &format!("{}_callable_cast_done", label_prefix));
    }
    emitter.label(&format!("{}_callable_cast_done", label_prefix));
}

/// Converts the x86_64 boxed eval argument slot into a callable descriptor pointer.
pub(super) fn emit_x86_64_cast_eval_callable_arg(
    module: &Module,
    emitter: &mut Emitter,
    data: &mut DataSection,
    support: &EvalCallableDescriptorSupport,
    label_prefix: &str,
    fail_label: &str,
    context_frame_offset: usize,
) {
    let string_label = format!("{}_callable_string", label_prefix);
    let array_label = format!("{}_callable_array", label_prefix);
    let object_label = format!("{}_callable_object", label_prefix);
    let dynamic_label = format!("{}_callable_dynamic", label_prefix);
    let miss_label = if support.has_dynamic_descriptor() {
        dynamic_label.as_str()
    } else {
        fail_label
    };
    emitter.instruction("mov rax, QWORD PTR [rbp - 40]");                       // reload the boxed eval argument for callable validation
    emitter.instruction("call __rt_mixed_unbox");                               // expose the eval callable tag and payload words
    emitter.instruction("cmp rax, 1");                                          // runtime tag 1 means a string callable name
    emitter.instruction(&format!("je {}", string_label));                       // resolve string callables through descriptor metadata
    emitter.instruction("cmp rax, 4");                                          // runtime tag 4 means an indexed callable array
    emitter.instruction(&format!("je {}", array_label));                        // resolve static callable arrays through descriptor metadata
    emitter.instruction("cmp rax, 5");                                          // runtime tag 5 means an associative callable array
    emitter.instruction(&format!("je {}", array_label));                        // resolve static callable arrays with numeric keys
    emitter.instruction("cmp rax, 6");                                          // runtime tag 6 means an invokable object candidate
    emitter.instruction(&format!("je {}", object_label));                       // resolve invokable objects through descriptor metadata
    abi::emit_jump(emitter, miss_label);
    emitter.label(&string_label);
    abi::emit_push_reg_pair(emitter, "rdi", "rdx");
    emit_eval_string_callable_descriptor_lookup(
        module,
        emitter,
        data,
        support,
        label_prefix,
        miss_label,
        "rax",
    );
    abi::emit_jump(emitter, &format!("{}_callable_cast_done", label_prefix));
    emitter.label(&array_label);
    emit_x86_64_eval_callable_array_selector_slots(module, emitter);
    emit_eval_callable_array_descriptor_lookup(
        emitter,
        data,
        support,
        label_prefix,
        miss_label,
        "rax",
    );
    abi::emit_jump(emitter, &format!("{}_callable_cast_done", label_prefix));
    emitter.label(&object_label);
    abi::emit_push_reg(emitter, "rdi");
    emit_eval_invokable_object_descriptor_lookup(
        emitter,
        support,
        label_prefix,
        miss_label,
        "rax",
    );
    if support.has_dynamic_descriptor() {
        emitter.label(&dynamic_label);
        emit_x86_64_eval_dynamic_callable_descriptor(
            module,
            emitter,
            support,
            fail_label,
            "rax",
            context_frame_offset,
        );
        abi::emit_jump(emitter, &format!("{}_callable_cast_done", label_prefix));
    }
    emitter.label(&format!("{}_callable_cast_done", label_prefix));
}

/// Materializes a runtime descriptor that dispatches a callable through magician on ARM64.
fn emit_aarch64_eval_dynamic_callable_descriptor(
    module: &Module,
    emitter: &mut Emitter,
    support: &EvalCallableDescriptorSupport,
    fail_label: &str,
    result_reg: &str,
) {
    let descriptor_label = support
        .dynamic_descriptor_label
        .as_deref()
        .expect("dynamic eval callable descriptor must exist");
    let is_callable_symbol = module.target.extern_symbol("__elephc_eval_is_callable");
    emitter.instruction(&format!(
        "ldr x0, [x29, #{}]",
        AARCH64_EVAL_CONTEXT_FROM_FP_OFFSET
    ));                                                                          // load the active eval context for dynamic callable validation
    emitter.instruction(&format!("cbz x0, {}", fail_label));                    // reject dynamic eval callables when no context is active
    emitter.instruction("ldr x1, [x29, #-16]");                                 // pass the original boxed eval callback value
    abi::emit_call_label(emitter, &is_callable_symbol);
    emitter.instruction("cmp w0, #0");                                          // check whether magician accepts the callback value
    emitter.instruction(&format!("b.eq {}", fail_label));                       // reject non-callable eval values
    emitter.instruction("ldr x0, [x29, #-16]");                                 // reload the boxed callback value to retain it
    emitter.instruction("bl __rt_incref");                                      // retain the callback for descriptor capture ownership
    abi::emit_push_reg(emitter, "x0");
    abi::emit_load_int_immediate(
        emitter,
        "x0",
        (callable_descriptor::CALLABLE_DESC_RUNTIME_CAPTURE_OFFSET
            + EVAL_DYNAMIC_CALLABLE_CAPTURE_BYTES) as i64,
    );
    emitter.instruction("bl __rt_heap_alloc");                                  // allocate runtime descriptor storage with eval captures
    callable_descriptor::emit_copy_static_descriptor_to_runtime(emitter, "x0", descriptor_label);
    emitter.instruction(&format!(
        "ldr x10, [x29, #{}]",
        AARCH64_EVAL_CONTEXT_FROM_FP_OFFSET
    ));                                                                          // reload the active eval context for descriptor capture 0
    abi::emit_store_to_address(
        emitter,
        "x10",
        "x0",
        dynamic_capture_offset(EVAL_DYNAMIC_CONTEXT_CAPTURE),
    );
    abi::emit_load_temporary_stack_slot(emitter, "x10", 0);
    abi::emit_store_to_address(
        emitter,
        "x10",
        "x0",
        dynamic_capture_offset(EVAL_DYNAMIC_CALLBACK_CAPTURE),
    );
    abi::emit_release_temporary_stack(emitter, 16);
    if result_reg != "x0" {
        emitter.instruction(&format!("mov {}, x0", result_reg));                // return the dynamic eval callable descriptor
    }
}

/// Materializes a runtime descriptor that dispatches a callable through magician on x86_64.
fn emit_x86_64_eval_dynamic_callable_descriptor(
    module: &Module,
    emitter: &mut Emitter,
    support: &EvalCallableDescriptorSupport,
    fail_label: &str,
    result_reg: &str,
    context_frame_offset: usize,
) {
    let descriptor_label = support
        .dynamic_descriptor_label
        .as_deref()
        .expect("dynamic eval callable descriptor must exist");
    let is_callable_symbol = module.target.extern_symbol("__elephc_eval_is_callable");
    emitter.instruction(&format!(
        "mov rdi, QWORD PTR [rbp - {}]",
        context_frame_offset
    ));                                                                          // load the active eval context for dynamic callable validation
    emitter.instruction("test rdi, rdi");                                       // check whether a context was passed by magician
    emitter.instruction(&format!("jz {}", fail_label));                         // reject dynamic eval callables when no context is active
    emitter.instruction("mov rsi, QWORD PTR [rbp - 40]");                       // pass the original boxed eval callback value
    abi::emit_call_label(emitter, &is_callable_symbol);
    emitter.instruction("test eax, eax");                                       // check whether magician accepts the callback value
    emitter.instruction(&format!("jz {}", fail_label));                         // reject non-callable eval values
    emitter.instruction("mov rax, QWORD PTR [rbp - 40]");                       // reload the boxed callback value to retain it
    emitter.instruction("call __rt_incref");                                    // retain the callback for descriptor capture ownership
    abi::emit_push_reg(emitter, "rax");
    abi::emit_load_int_immediate(
        emitter,
        "rax",
        (callable_descriptor::CALLABLE_DESC_RUNTIME_CAPTURE_OFFSET
            + EVAL_DYNAMIC_CALLABLE_CAPTURE_BYTES) as i64,
    );
    emitter.instruction("call __rt_heap_alloc");                                // allocate runtime descriptor storage with eval captures
    callable_descriptor::emit_copy_static_descriptor_to_runtime(emitter, "rax", descriptor_label);
    emitter.instruction(&format!(
        "mov r10, QWORD PTR [rbp - {}]",
        context_frame_offset
    ));                                                                          // reload the active eval context for descriptor capture 0
    abi::emit_store_to_address(
        emitter,
        "r10",
        "rax",
        dynamic_capture_offset(EVAL_DYNAMIC_CONTEXT_CAPTURE),
    );
    abi::emit_load_temporary_stack_slot(emitter, "r10", 0);
    abi::emit_store_to_address(
        emitter,
        "r10",
        "rax",
        dynamic_capture_offset(EVAL_DYNAMIC_CALLBACK_CAPTURE),
    );
    abi::emit_release_temporary_stack(emitter, 16);
    if result_reg != "rax" {
        emitter.instruction(&format!("mov {}, rax", result_reg));               // return the dynamic eval callable descriptor
    }
}

/// Looks up a descriptor by the string callable currently saved on the temp stack.
fn emit_eval_string_callable_descriptor_lookup(
    module: &Module,
    emitter: &mut Emitter,
    data: &mut DataSection,
    support: &EvalCallableDescriptorSupport,
    label_prefix: &str,
    fail_label: &str,
    result_reg: &str,
) {
    let done_label = format!("{}_callable_done", label_prefix);
    let miss_label = format!("{}_callable_missing", label_prefix);
    if support.is_empty() {
        abi::emit_release_temporary_stack(emitter, 16);
        abi::emit_jump(emitter, fail_label);
        return;
    }
    let selector = RuntimeCallableSelector::StringNameStack {
        ptr_offset: 0,
        len_offset: 8,
        call_reg: result_reg,
    };
    let mut legacy_ctx = super::lower_inst::legacy_context_from_eir_module(module);
    for case in support
        .string_cases
        .iter()
        .chain(support.static_array_cases.iter().map(|case| &case.case))
    {
        let next_case = legacy_ctx.next_label("eval_callable_next");
        callable_dispatch::emit_branch_if_callable_case_mismatch(
            &selector,
            case,
            &next_case,
            emitter,
            &mut legacy_ctx,
            data,
        );
        abi::emit_jump(emitter, &done_label);
        emitter.label(&next_case);
    }
    abi::emit_jump(emitter, &miss_label);
    emitter.label(&miss_label);
    abi::emit_release_temporary_stack(emitter, 16);
    abi::emit_jump(emitter, fail_label);
    emitter.label(&done_label);
    abi::emit_release_temporary_stack(emitter, 16);
}

/// Saves the receiver and method slots from an ARM64 boxed eval callable array.
fn emit_aarch64_eval_callable_array_selector_slots(module: &Module, emitter: &mut Emitter) {
    emit_aarch64_eval_callable_array_slot(module, emitter, 0);
    emit_aarch64_push_mixed_unbox_payload(emitter);
    emit_aarch64_eval_callable_array_slot(module, emitter, 1);
    emit_aarch64_push_mixed_unbox_payload(emitter);
}

/// Saves the receiver and method slots from an x86_64 boxed eval callable array.
fn emit_x86_64_eval_callable_array_selector_slots(module: &Module, emitter: &mut Emitter) {
    emit_x86_64_eval_callable_array_slot(module, emitter, 0);
    emit_x86_64_push_mixed_unbox_payload(emitter);
    emit_x86_64_eval_callable_array_slot(module, emitter, 1);
    emit_x86_64_push_mixed_unbox_payload(emitter);
}

/// Loads and unboxes one ARM64 callable-array slot through eval's array reader.
fn emit_aarch64_eval_callable_array_slot(module: &Module, emitter: &mut Emitter, index: usize) {
    let value_int_symbol = module.target.extern_symbol("__elephc_eval_value_int");
    let array_get_symbol = module.target.extern_symbol("__elephc_eval_value_array_get");
    abi::emit_load_int_immediate(emitter, "x0", index as i64);
    abi::emit_call_label(emitter, &value_int_symbol);
    emitter.instruction("str x0, [sp, #-16]!");                                 // preserve the boxed callable-array index
    emitter.instruction("ldr x1, [sp]");                                        // pass the boxed selector index to eval's array reader
    emitter.instruction("ldr x0, [x29, #-16]");                                 // pass the boxed callable array to eval's array reader
    abi::emit_call_label(emitter, &array_get_symbol);
    emitter.instruction("add sp, sp, #16");                                     // discard the temporary boxed selector index
    emitter.instruction("bl __rt_mixed_unbox");                                 // expose the callable-array selector slot tag and payload
}

/// Loads and unboxes one x86_64 callable-array slot through eval's array reader.
fn emit_x86_64_eval_callable_array_slot(module: &Module, emitter: &mut Emitter, index: usize) {
    let value_int_symbol = module.target.extern_symbol("__elephc_eval_value_int");
    let array_get_symbol = module.target.extern_symbol("__elephc_eval_value_array_get");
    abi::emit_load_int_immediate(emitter, "rdi", index as i64);
    abi::emit_call_label(emitter, &value_int_symbol);
    abi::emit_push_reg(emitter, "rax");
    emitter.instruction("mov rsi, QWORD PTR [rsp]");                            // pass the boxed selector index to eval's array reader
    emitter.instruction("mov rdi, QWORD PTR [rbp - 40]");                       // pass the boxed callable array to eval's array reader
    abi::emit_call_label(emitter, &array_get_symbol);
    emitter.instruction("add rsp, 16");                                         // discard the temporary boxed selector index
    emitter.instruction("call __rt_mixed_unbox");                               // expose the callable-array selector slot tag and payload
}

/// Preserves the current ARM64 mixed-unbox tag and payload on the temp stack.
fn emit_aarch64_push_mixed_unbox_payload(emitter: &mut Emitter) {
    abi::emit_push_reg_pair(emitter, "x1", "x2");
    abi::emit_push_reg(emitter, "x0");
}

/// Preserves the current x86_64 mixed-unbox tag and payload on the temp stack.
fn emit_x86_64_push_mixed_unbox_payload(emitter: &mut Emitter) {
    abi::emit_push_reg_pair(emitter, "rdi", "rdx");
    abi::emit_push_reg(emitter, "rax");
}

/// Looks up a descriptor from saved callable-array selector slots.
fn emit_eval_callable_array_descriptor_lookup(
    emitter: &mut Emitter,
    data: &mut DataSection,
    support: &EvalCallableDescriptorSupport,
    label_prefix: &str,
    fail_label: &str,
    result_reg: &str,
) {
    let done_label = format!("{}_callable_array_done", label_prefix);
    let miss_label = format!("{}_callable_array_missing", label_prefix);
    if support.array_cases_empty() {
        abi::emit_release_temporary_stack(emitter, MIXED_SELECTOR_BYTES);
        abi::emit_jump(emitter, fail_label);
        return;
    }
    for (index, case) in support.instance_array_cases.iter().enumerate() {
        let next_case = format!("{}_callable_array_instance_next_{}", label_prefix, index);
        emit_branch_if_instance_callable_array_case_mismatch(
            emitter,
            data,
            case,
            &next_case,
        );
        emit_runtime_descriptor_with_saved_receiver_capture(
            emitter,
            &case.case.descriptor_label,
            MIXED_RECEIVER_PAYLOAD_OFFSET,
            result_reg,
        );
        abi::emit_jump(emitter, &done_label);
        emitter.label(&next_case);
    }
    for (index, case) in support.static_array_cases.iter().enumerate() {
        let next_case = format!("{}_callable_array_next_{}", label_prefix, index);
        emit_branch_if_static_callable_array_case_mismatch(
            emitter,
            data,
            case,
            &next_case,
        );
        abi::emit_symbol_address(emitter, result_reg, &case.case.descriptor_label);
        abi::emit_jump(emitter, &done_label);
        emitter.label(&next_case);
    }
    abi::emit_jump(emitter, &miss_label);
    emitter.label(&miss_label);
    abi::emit_release_temporary_stack(emitter, MIXED_SELECTOR_BYTES);
    abi::emit_jump(emitter, fail_label);
    emitter.label(&done_label);
    abi::emit_release_temporary_stack(emitter, MIXED_SELECTOR_BYTES);
}

/// Looks up a descriptor from a saved invokable-object receiver.
fn emit_eval_invokable_object_descriptor_lookup(
    emitter: &mut Emitter,
    support: &EvalCallableDescriptorSupport,
    label_prefix: &str,
    fail_label: &str,
    result_reg: &str,
) {
    let done_label = format!("{}_callable_object_done", label_prefix);
    let miss_label = format!("{}_callable_object_missing", label_prefix);
    if support.object_cases_empty() {
        abi::emit_release_temporary_stack(emitter, SAVED_OBJECT_RECEIVER_BYTES);
        abi::emit_jump(emitter, fail_label);
        return;
    }
    for (index, case) in support.object_cases.iter().enumerate() {
        let next_case = format!("{}_callable_object_next_{}", label_prefix, index);
        emit_branch_if_receiver_class_id_mismatch(
            emitter,
            case.class_id,
            0,
            &next_case,
        );
        emit_runtime_descriptor_with_saved_receiver_capture(
            emitter,
            &case.case.descriptor_label,
            0,
            result_reg,
        );
        abi::emit_jump(emitter, &done_label);
        emitter.label(&next_case);
    }
    abi::emit_jump(emitter, &miss_label);
    emitter.label(&miss_label);
    abi::emit_release_temporary_stack(emitter, SAVED_OBJECT_RECEIVER_BYTES);
    abi::emit_jump(emitter, fail_label);
    emitter.label(&done_label);
    abi::emit_release_temporary_stack(emitter, SAVED_OBJECT_RECEIVER_BYTES);
}

/// Branches unless saved selector slots match one instance callable-array case.
fn emit_branch_if_instance_callable_array_case_mismatch(
    emitter: &mut Emitter,
    data: &mut DataSection,
    case: &RuntimeInstanceMethodCallableCase,
    next_label: &str,
) {
    emit_branch_if_stack_tag_mismatch(
        emitter,
        MIXED_RECEIVER_TAG_OFFSET,
        MIXED_TAG_OBJECT,
        next_label,
    );
    emit_branch_if_stack_tag_mismatch(
        emitter,
        MIXED_METHOD_TAG_OFFSET,
        MIXED_TAG_STRING,
        next_label,
    );
    emit_branch_if_receiver_class_id_mismatch(
        emitter,
        case.class_id,
        MIXED_RECEIVER_PAYLOAD_OFFSET,
        next_label,
    );
    emit_branch_if_stack_string_mismatch(
        emitter,
        data,
        MIXED_METHOD_PAYLOAD_OFFSET,
        MIXED_METHOD_PAYLOAD_OFFSET + 8,
        case.method_name.as_bytes(),
        next_label,
    );
}

/// Branches unless saved selector slots match one static callable-array case.
fn emit_branch_if_static_callable_array_case_mismatch(
    emitter: &mut Emitter,
    data: &mut DataSection,
    case: &RuntimeStaticMethodCallableCase,
    next_label: &str,
) {
    emit_branch_if_stack_tag_mismatch(
        emitter,
        MIXED_RECEIVER_TAG_OFFSET,
        MIXED_TAG_STRING,
        next_label,
    );
    emit_branch_if_stack_tag_mismatch(
        emitter,
        MIXED_METHOD_TAG_OFFSET,
        MIXED_TAG_STRING,
        next_label,
    );
    emit_branch_if_static_class_string_mismatch(
        emitter,
        data,
        MIXED_RECEIVER_PAYLOAD_OFFSET,
        MIXED_RECEIVER_PAYLOAD_OFFSET + 8,
        &case.class_name,
        next_label,
    );
    emit_branch_if_stack_string_mismatch(
        emitter,
        data,
        MIXED_METHOD_PAYLOAD_OFFSET,
        MIXED_METHOD_PAYLOAD_OFFSET + 8,
        case.method_name.as_bytes(),
        next_label,
    );
}

/// Branches when the saved receiver object's class id does not match `class_id`.
fn emit_branch_if_receiver_class_id_mismatch(
    emitter: &mut Emitter,
    class_id: u64,
    receiver_offset: usize,
    next_label: &str,
) {
    match emitter.target.arch {
        crate::codegen::platform::Arch::AArch64 => {
            abi::emit_load_temporary_stack_slot(emitter, "x9", receiver_offset);
            emitter.instruction(&format!("cbz x9, {}", next_label));            // reject null receiver pointers before reading their class id
            emitter.instruction("ldr x10, [x9]");                               // load the receiver runtime class id from the object header
            abi::emit_load_int_immediate(emitter, "x11", class_id as i64);
            emitter.instruction("cmp x10, x11");                                // compare receiver class id against this callable case
            emitter.instruction(&format!("b.ne {}", next_label));               // try the next callable target when the receiver class differs
        }
        crate::codegen::platform::Arch::X86_64 => {
            abi::emit_load_temporary_stack_slot(emitter, "r10", receiver_offset);
            emitter.instruction("test r10, r10");                               // reject null receiver pointers before reading their class id
            emitter.instruction(&format!("je {}", next_label));                 // try the next callable target when the receiver pointer is null
            emitter.instruction("mov r11, QWORD PTR [r10]");                    // load the receiver runtime class id from the object header
            abi::emit_load_int_immediate(emitter, "r10", class_id as i64);
            emitter.instruction("cmp r11, r10");                                // compare receiver class id against this callable case
            emitter.instruction(&format!("jne {}", next_label));                // try the next callable target when the receiver class differs
        }
    }
}

/// Allocates a runtime descriptor and captures the saved receiver object.
fn emit_runtime_descriptor_with_saved_receiver_capture(
    emitter: &mut Emitter,
    descriptor_label: &str,
    receiver_offset: usize,
    result_reg: &str,
) {
    let total_bytes = callable_descriptor::CALLABLE_DESC_RUNTIME_CAPTURE_OFFSET + 16;
    match emitter.target.arch {
        crate::codegen::platform::Arch::AArch64 => {
            abi::emit_load_temporary_stack_slot(emitter, "x0", receiver_offset);
            emitter.instruction("bl __rt_incref");                              // retain the receiver for the runtime callable descriptor
            abi::emit_push_reg(emitter, "x0");
            abi::emit_load_int_immediate(emitter, "x0", total_bytes as i64);
            emitter.instruction("bl __rt_heap_alloc");                          // allocate receiver-bound callable descriptor storage
            callable_descriptor::emit_copy_static_descriptor_to_runtime(
                emitter,
                "x0",
                descriptor_label,
            );
            abi::emit_push_reg(emitter, "x0");
            abi::emit_load_temporary_stack_slot(emitter, "x11", 0);
            abi::emit_load_temporary_stack_slot(emitter, "x0", 16);
            callable_descriptor::emit_store_current_result_to_runtime_capture(
                emitter,
                "x11",
                0,
                &PhpType::Object(String::new()),
            );
            abi::emit_pop_reg(emitter, result_reg);
            abi::emit_release_temporary_stack(emitter, 16);
        }
        crate::codegen::platform::Arch::X86_64 => {
            abi::emit_load_temporary_stack_slot(emitter, "rax", receiver_offset);
            emitter.instruction("call __rt_incref");                            // retain the receiver for the runtime callable descriptor
            abi::emit_push_reg(emitter, "rax");
            abi::emit_load_int_immediate(emitter, "rax", total_bytes as i64);
            emitter.instruction("call __rt_heap_alloc");                        // allocate receiver-bound callable descriptor storage
            callable_descriptor::emit_copy_static_descriptor_to_runtime(
                emitter,
                "rax",
                descriptor_label,
            );
            abi::emit_push_reg(emitter, "rax");
            abi::emit_load_temporary_stack_slot(emitter, "rcx", 0);
            abi::emit_load_temporary_stack_slot(emitter, "rax", 16);
            callable_descriptor::emit_store_current_result_to_runtime_capture(
                emitter,
                "rcx",
                0,
                &PhpType::Object(String::new()),
            );
            abi::emit_pop_reg(emitter, result_reg);
            abi::emit_release_temporary_stack(emitter, 16);
        }
    }
}

/// Branches when a saved Mixed tag stack slot does not equal `expected_tag`.
fn emit_branch_if_stack_tag_mismatch(
    emitter: &mut Emitter,
    tag_offset: usize,
    expected_tag: i64,
    next_label: &str,
) {
    match emitter.target.arch {
        crate::codegen::platform::Arch::AArch64 => {
            abi::emit_load_temporary_stack_slot(emitter, "x9", tag_offset);
            emitter.instruction(&format!("cmp x9, #{}", expected_tag));         // compare the callable-array selector runtime tag
            emitter.instruction(&format!("b.ne {}", next_label));               // try the next callable-array target when the tag differs
        }
        crate::codegen::platform::Arch::X86_64 => {
            abi::emit_load_temporary_stack_slot(emitter, "r10", tag_offset);
            emitter.instruction(&format!("cmp r10, {}", expected_tag));         // compare the callable-array selector runtime tag
            emitter.instruction(&format!("jne {}", next_label));                // try the next callable-array target when the tag differs
        }
    }
}

/// Branches when a saved stack string does not match the expected PHP name.
fn emit_branch_if_stack_string_mismatch(
    emitter: &mut Emitter,
    data: &mut DataSection,
    ptr_offset: usize,
    len_offset: usize,
    expected: &[u8],
    next_label: &str,
) {
    let matched_label = format!("{}_matched", next_label);
    emit_stack_string_compare_branch(
        emitter,
        data,
        ptr_offset,
        len_offset,
        expected,
        &matched_label,
    );
    abi::emit_jump(emitter, next_label);
    emitter.label(&matched_label);
}

/// Branches when a saved class string does not match bare or leading-slash forms.
fn emit_branch_if_static_class_string_mismatch(
    emitter: &mut Emitter,
    data: &mut DataSection,
    ptr_offset: usize,
    len_offset: usize,
    class_name: &str,
    next_label: &str,
) {
    let matched_label = format!("{}_class_matched", next_label);
    emit_stack_string_compare_branch(
        emitter,
        data,
        ptr_offset,
        len_offset,
        class_name.as_bytes(),
        &matched_label,
    );
    let leading_slash = format!("\\{}", class_name);
    emit_stack_string_compare_branch(
        emitter,
        data,
        ptr_offset,
        len_offset,
        leading_slash.as_bytes(),
        &matched_label,
    );
    abi::emit_jump(emitter, next_label);
    emitter.label(&matched_label);
}

/// Compares a saved stack string with `expected` and branches on equality.
fn emit_stack_string_compare_branch(
    emitter: &mut Emitter,
    data: &mut DataSection,
    ptr_offset: usize,
    len_offset: usize,
    expected: &[u8],
    matched_label: &str,
) {
    let (expected_label, expected_len) = data.add_string(expected);
    match emitter.target.arch {
        crate::codegen::platform::Arch::AArch64 => {
            abi::emit_load_temporary_stack_slot(emitter, "x1", ptr_offset);
            abi::emit_load_temporary_stack_slot(emitter, "x2", len_offset);
            abi::emit_symbol_address(emitter, "x3", &expected_label);
            abi::emit_load_int_immediate(emitter, "x4", expected_len as i64);
            abi::emit_call_label(emitter, "__rt_strcasecmp");
            emitter.instruction("cmp x0, #0");                                  // check whether the runtime method string matched
            emitter.instruction(&format!("b.eq {}", matched_label));            // select this callable-array target when names match
        }
        crate::codegen::platform::Arch::X86_64 => {
            abi::emit_load_temporary_stack_slot(emitter, "rdi", ptr_offset);
            abi::emit_load_temporary_stack_slot(emitter, "rsi", len_offset);
            abi::emit_symbol_address(emitter, "rdx", &expected_label);
            abi::emit_load_int_immediate(emitter, "rcx", expected_len as i64);
            abi::emit_call_label(emitter, "__rt_strcasecmp");
            emitter.instruction("test rax, rax");                               // check whether the runtime method string matched
            emitter.instruction(&format!("je {}", matched_label));              // select this callable-array target when names match
        }
    }
}
